const PEPTIDE_GENERAL_GUIDE = [
 {
  "emoji": "ℹ️",
  "head": "General information",
  "body": "These notes apply across all DarDoc peptide protocols.\n\n**Prescription & sourcing** — All peptides require a UAE physician prescription and are compounded by DHA- and EDE-licensed pharmacies, with raw materials from FDA-inspected US facilities, lab-tested to at least 99% purity and sterility.\n\n**Delivery & storage** — Refrigerated peptides (injectable vials, nasal sprays, topical formulations) are delivered via temperature-controlled cold-chain courier; oral capsules ship at room temperature. Store refrigerated items at 2–8 °C in original packaging, away from light. Do not freeze. Once you first puncture a vial, use its contents within 28 days.\n\n**Travelling** — Peptides tolerate a few hours at room temperature; for longer trips carry them in an insulated cooler with ice packs (avoid direct ice contact). For air travel, keep your prescription and pharmacy documentation in your carry-on, with needles in original packaging.\n\n**When your package arrives** — If a shipment arrives warm, a vial looks cloudy or discoloured (other than the natural blue of GHK-Cu) or contains particles, or a seal is damaged — do not use it. Contact us for a replacement before starting.\n\n**Reaching us** — Routine questions (technique, supply, timing): secure patient portal, typically answered within one business day. Urgent concerns (significant side effects, injection-site infection, suspected allergic reaction): call our clinical line directly. For a severe allergic reaction — difficulty breathing, face or throat swelling — call local emergency services first, then notify us.\n\n**What this document is** — An educational and instructional overview to support your prescribed protocol. It is not a substitute for your physician's advice."
 }
];

function guideContentFor(medication, route) {
  const variants = PATIENT_GUIDES[medication];
  if (!variants || !variants.length) return null;
  return variants.find((v) => v.route === route) || variants[0];
}
